mapper.select:
select
a.privilege_grant_id,
a.grant_type,
a.oper_type,
a.grant_obj_type,
a.grant_obj_id,
a.eff_date,
a.exp_date,
a.status_cd,
a.grant_to_obj_type,
a.grant_to_obj_id,
a.grant_to_type,
a.allow_unsubscribe
from au_privilege_grant a


        AND a.grant_type =#{grantType}



            #{item}



        AND a.grant_obj_type =#{grantObjType}



            #{item}



        AND a.grant_obj_id =#{grantObjId}



            #{item}



        AND a.grant_to_type = #{color}


        AND a.grant_to_obj_type =#{grantToObjType}



            #{item}



        AND a.grant_to_obj_id =#{grantToObjId}



            AND a.status_cd =#{statusCd}


            AND status_cd ='A'

select grant_type,
oper_type,
grant_obj_type,
grant_obj_id
from au_privilege_grant

    and status_cd ='A' and grant_obj_type ='AGENT'

        and grant_type =#{digitalEmployeeAuthQo.grantType}


        and (red_to_obj_id =#{digitalEmployeeAuthQo.grantObjId}
        or
        black_to_obj_id = #{digitalEmployeeAuthQo.grantObjId}
        )


        and (red_to_obj_type =#{digitalEmployeeAuthQo.grantToObjType}
        or
        black_to_obj_type =#{digitalEmployeeAuthQo.grantToObjType}
        )

select a.resource_id, a.system_code, a.resource_source_pk_id, a.resource_biz_type, a.resource_type, a.resource_name, a.resource_desc, a.avatar, a.sample, a.tags, a.resource_version_id, a.host_type, a.catalog_id, a.man_org_id, a.man_user_id, a.index_list, a.create_by, a.create_time, a.update_by, a.update_time, a.com_acct_id, a.resource_status, a.resource_d_verid, a.resource_r_verid, a.resource_code, a.publish_time, a.shelf_time, a.unshelf_time, a.auth_status, a.publish_portal, a.parent_resource_id, a.publish_type, a.owner_type, b.user_name as createUserName from ss_resource a left join po_users b on a.create_by = b.user_id left join ( select grant_obj_id, sum(case when grant_to_type = 'RED' and status_cd = 'A' then 1 else 0 end) as red_count, sum(case when grant_to_type = 'BLACK' and status_cd = 'A' then 1 else 0 end) as black_count, sum(case when grant_type = 'ALLOW_MANAGE' and grant_to_type = 'RED' and status_cd = 'A' then 1 else 0 end) as allow_manage_count from au_privilege_grant where grant_type in ('AVAILABLE_USE', 'FORCE_USE', 'ALLOW_MANAGE') and status_cd = 'A'
or (grant_to_obj_type = 'ORG' and grant_to_obj_id in
#{orgId}
)
or (grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId})
or (grant_to_obj_type = 'POST' and grant_to_obj_id in
#{positionId}
)
or (grant_to_obj_type = 'STATION' and grant_to_obj_id = #{userStationId})
group by grant_obj_id ) k on a.resource_id = k.grant_obj_id left join ( select grant_obj_id, count(1) as pending_apply_count, sum(case when grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId} then 1 else 0 end) as my_pending_apply_count from au_privilege_grant where grant_type = 'AVAILABLE_USE' and grant_to_type = 'RED' and status_cd = 'P' group by grant_obj_id ) p on a.resource_id = p.grant_obj_id
and (
(a.owner_type = 'personal_default' and a.resource_id = #{defaultPersonalResourceId}) or
a.resource_status = #{resourceStatus}
1 = 1
a.resource_status = 2
) and (k.black_count = 0 or k.black_count is null)
and a.owner_type = 'enterprise'
and ( (a.owner_type = 'personal' and (k.red_count > 0 or a.create_by = #{userId}))
or (a.owner_type = 'personal_default' and a.resource_id = #{defaultPersonalResourceId})
)
and ( k.red_count > 0 or a.create_by = #{userId} )
and a.owner_type = #{ownerType}
and a.resource_biz_type in
#{bizType}
and a.catalog_id in
#{catalogIdItem}
and a.catalog_id = #{catalogId}
and a.man_org_id in
#{orgId}
and a.create_by = #{userId}
and (a.create_by is null or a.create_by != #{userId}) and (k.red_count > 0 or k.allow_manage_count > 0)
and coalesce(p.pending_apply_count, 0) > 0 and ( a.create_by = #{userId} or k.allow_manage_count > 0
or 1 = 1
or exists ( select 1 from po_organization org where org.org_id = a.man_org_id and (
org.path_code = #{pathCode} or org.path_code like concat(#{pathCode}, '.%')
) )
or (a.owner_type = 'personal_default' and a.resource_id = #{defaultPersonalResourceId})
)
and coalesce(p.my_pending_apply_count, 0) > 0
and (a.resource_name like concat('%', #{keyword}, '%') or a.resource_desc like concat('%', #{keyword}, '%'))
order by COALESCE(a.update_time, '1970-01-01 00:00:00') desc, a.create_time desc

select privilege_grant_id, grant_type, oper_type, grant_obj_type, grant_obj_id, grant_to_obj_type, grant_to_obj_id, grant_to_type from au_privilege_grant
and status_cd ='A' and grant_to_obj_id is not null and grant_to_obj_type is not null
and grant_type =#{grantType}
and grant_obj_type =#{grantObjType}
and grant_obj_id =#{grantObjId}
and grant_to_type =#{color}

select grant_obj_id from au_privilege_grant where status_cd = 'A' and grant_type in('ALLOW_MANAGE','OWNER') and grant_to_type ='RED' and grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId}
and grant_obj_type in
#{item}

SELECT a.privilege_grant_id, a.grant_type, a.oper_type, a.grant_obj_type, a.grant_obj_id, a.grant_to_obj_id, a.grant_to_obj_type, a.grant_to_type, CASE WHEN a.grant_to_obj_type = 'ORG' THEN o.org_name WHEN a.grant_to_obj_type = 'USER' THEN u.user_name WHEN a.grant_to_obj_type = 'POST' THEN p.position_name ELSE NULL END AS memberName, add_user.user_name AS createdBy FROM ( SELECT privilege_grant_id, grant_type, grant_to_obj_id, grant_to_obj_type, grant_to_type, oper_type, grant_obj_type, grant_obj_id, create_staff FROM au_privilege_grant WHERE status_cd = 'A' and grant_to_obj_id is not null and grant_to_type = 'RED' and grant_type != 'FORCE_USE'
AND grant_obj_type = #{priviledgeQo.grantObjType}
AND grant_obj_id = #{priviledgeQo.grantObjId}
) a LEFT JOIN po_organization o ON a.grant_to_obj_id = o.org_id LEFT JOIN po_users u ON a.grant_to_obj_id = u.user_id LEFT JOIN po_users add_user ON a.create_staff = add_user.user_id LEFT JOIN po_position p on a.grant_to_obj_id = p.position_id
WHERE ( o.org_name LIKE CONCAT('%', #{priviledgeQo.keyWord}, '%') OR u.user_name LIKE CONCAT('%', #{priviledgeQo.keyWord}, '%') OR p.position_name LIKE CONCAT('%', #{priviledgeQo.keyWord}, '%') )

select a.privilege_grant_id, a.grant_type, a.oper_type, a.grant_obj_type, a.grant_obj_id, a.grant_to_obj_id, a.grant_to_obj_type, a.grant_to_type from au_privilege_grant a left join po_organization b on a.grant_to_obj_id = b.org_id and a.grant_to_obj_type = 'ORG' where a.status_cd = 'A'
and a.grant_type = #{grantType}
and a.grant_obj_id = #{grantObjId}
order by b.org_level asc,a.create_date desc

select a.grant_obj_id, a.grant_to_type, a.grant_to_obj_id, a.grant_to_obj_type, a.status_cd, b.path_code from au_privilege_grant a left join po_organization b on a.grant_to_obj_id = b.org_id and a.grant_to_obj_type = 'ORG' where a.grant_type = 'AVAILABLE_USE' and a.oper_type = 'READ' and a.grant_obj_type = 'DIG_EMPLOYEE' and a.status_cd in ('A', 'S')
and a.grant_obj_id in
#{item}

SELECT a.grant_obj_id, a.grant_obj_type, a.grant_to_type, a.grant_to_obj_id, a.grant_to_obj_type, a.status_cd, b.path_code as org_path, c.station_id_path as station_path FROM au_privilege_grant a LEFT JOIN po_organization b ON a.grant_to_obj_id = b.org_id AND a.grant_to_obj_type = 'ORG' LEFT JOIN po_station c ON a.grant_to_obj_id = c.station_id AND a.grant_to_obj_type = 'STATION' WHERE a.grant_obj_id IN
#{resourceId}
AND a.status_cd = 'A' AND a.oper_type = 'READ' AND a.grant_type IN
#{grantType}

select
a.privilege_grant_id,
a.grant_type,
a.oper_type,
a.grant_obj_type,
a.grant_obj_id,
sr.resource_name as grant_obj_name,
sr.resource_desc as grant_obj_desc,
a.eff_date,
a.exp_date,
a.status_cd,
a.grant_to_obj_type,
a.grant_to_obj_id,
a.grant_to_type,
a.allow_unsubscribe
from au_privilege_grant a left join ss_resource sr on a.grant_obj_id = sr.resource_id


        AND a.grant_type =#{grantType}



            #{item}



        AND a.grant_obj_type =#{grantObjType}



            #{item}



        AND a.grant_obj_id =#{grantObjId}



            #{item}



        AND a.grant_to_type = #{color}


        AND a.grant_to_obj_type =#{grantToObjType}



            #{item}



        AND a.grant_to_obj_id =#{grantToObjId}



            AND a.status_cd =#{statusCd}


            AND status_cd ='A'

select a.grant_obj_id, a.grant_to_obj_id, b.user_name from au_privilege_grant a left join po_users b on a.grant_to_obj_id = b.user_id where grant_type = 'ALLOW_MANAGE' and grant_to_obj_type ='USER' and status_cd = 'A'
and grant_obj_id in
#{item}

SELECT a.resource_id, a.system_code, a.resource_source_pk_id, a.resource_biz_type, a.resource_type, a.resource_name, a.resource_code, a.resource_desc, a.tags, a.catalog_id, a.man_org_id, a.man_user_id, a.index_list, a.create_by, a.create_time, a.com_acct_id, a.resource_status, a.publish_time, a.shelf_time, a.unshelf_time, b.catalog_name, c.user_name AS createUserName, d.org_name AS manOrgName, CASE WHEN (k.black_count = 0 OR k.black_count IS NULL) AND k.red_count > 0 THEN TRUE ELSE FALSE END AS hasPermission FROM ss_resource a LEFT JOIN ss_resource_catalog b ON a.catalog_id = b.catalog_id LEFT JOIN po_users c ON a.create_by = c.user_id LEFT JOIN po_organization d ON a.man_org_id = d.org_id LEFT JOIN ( SELECT grant_obj_id, SUM(CASE WHEN grant_to_type = 'RED' AND status_cd = 'A' THEN 1 ELSE 0 END) AS red_count, SUM(CASE WHEN grant_to_type = 'BLACK' AND status_cd = 'A' THEN 1 ELSE 0 END) AS black_count FROM au_privilege_grant WHERE grant_type IN ('AVAILABLE_USE', 'FORCE_USE','ALLOW_MANAGE')
#{item}
AND status_cd = 'A'
OR ( grant_to_obj_type = 'ORG' AND grant_to_obj_id IN
#{orgId}
)
OR (grant_to_obj_type = 'USER' AND grant_to_obj_id = #{userId})
OR ( grant_to_obj_type = 'POST' AND grant_to_obj_id IN
#{positionId}
)
OR (grant_to_obj_type = 'STATION' AND grant_to_obj_id = #{userStationId})
GROUP BY grant_obj_id ) k ON a.resource_id = k.grant_obj_id
AND EXISTS ( SELECT 1 FROM au_privilege_grant au WHERE au.status_cd = 'A' AND au.grant_obj_id = a.resource_id
#{item}
AND au.grant_to_obj_type = #{grantToObjType}
AND au.grant_to_obj_id = #{grantToObjId}
)

select a.resource_id as obj_id, a.resource_id, a.resource_biz_type, a.create_by, a.resource_name, a.resource_desc, a.create_time, a.resource_status, a.man_org_id, a.shelf_time, a.unshelf_time, a.publish_time, cat.catalog_name, d.org_name as man_org_name, coalesce(k.red_count, 0) as red_count, coalesce(k.black_count, 0) as black_count, coalesce(k.force_use_count, 0) as force_use_count, coalesce(k.available_use_count, 0) as available_use_count, coalesce(k.allow_manage_count, 0) as allow_manage_count from ss_resource a left join ss_resource_catalog cat on a.catalog_id = cat.catalog_id left join po_organization d on a.man_org_id = d.org_id left join ( select grant_obj_id, sum(case when grant_to_type = 'RED' and status_cd = 'A' then 1 else 0 end) as red_count, sum(case when grant_to_type = 'BLACK' and status_cd = 'A' then 1 else 0 end) as black_count, sum(case when grant_type = 'FORCE_USE' and status_cd = 'A' then 1 else 0 end) as force_use_count, sum(case when grant_type = 'AVAILABLE_USE' and status_cd = 'A' then 1 else 0 end) as available_use_count, sum(case when grant_type = 'ALLOW_MANAGE' and status_cd = 'A' then 1 else 0 end) as allow_manage_count from au_privilege_grant where grant_type in ('AVAILABLE_USE', 'FORCE_USE', 'ALLOW_MANAGE') and grant_obj_type = 'DIG_EMPLOYEE' and status_cd in ('A')
or ( grant_to_obj_type = 'ORG' and grant_to_obj_id in
#{orgId}
)
or (grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId})
or ( grant_to_obj_type = 'POST' and grant_to_obj_id in
#{positionId}
)
or (grant_to_obj_type = 'STATION' and grant_to_obj_id = #{userStationId})
group by grant_obj_id ) k on a.resource_id = k.grant_obj_id
and a.resource_biz_type = 'DIG_EMPLOYEE' and a.resource_status = 2
and a.resource_name like concat('%', #{keyword}, '%')
order by a.create_time desc, a.update_time desc
